class Solution {
public:
    double new21Game(int n, int k, int maxPts) {
        double res = 0.0;
        double sum = 0.0;
        for (int i = k; i <= n; i++) {
            sum += 1.0;
            if (i <= k + maxPts) {
                sum += (i - k + 1);
            }
        }
        if (k > 0) {
            res = sum / (1.0 + maxPts);
        } else {
            res = 1.0;
        }
        for (int i = k - 1; i >= 1; i--) {
            sum -= (i - k + 1);
            res += sum / (1.0 + maxPts);
        }
        return res;
    }
};
